mapper.select:
SELECT id, employee_id, task_id, start_time, end_time, description, created_at
FROM time_records
WHERE id = #{id}

SELECT id, employee_id, task_id, start_time, end_time, description, created_at
FROM time_records
WHERE employee_id = #{employeeId}
  AND start_time >= #{startDate}
  AND end_time <= #{endDate}
ORDER BY start_time DESC
